import { describe, expect, it } from 'vitest';
import type { IPlugin } from '../../../../../src/core/plugins/types/contracts';
import {
  toProjectedConnectionsFromFileAnalysis,
  withPluginProvenance,
} from '../../../../../src/core/plugins/routing/router/results/project';

describe('routing/results/project', () => {
  it('adds the plugin id to relations that do not already have provenance', () => {
    const plugin = { id: 'plugin' } as IPlugin;

    expect(withPluginProvenance(plugin, {
      filePath: 'src/app.ts',
      edgeTypes: [],
      nodeTypes: [],
      nodes: [],
      relations: [
        { kind: 'import', sourceId: 'plugin:import', fromFilePath: 'src/app.ts', toFilePath: 'src/lib.ts' },
        {
          kind: 'import',
          sourceId: 'plugin:kept',
          fromFilePath: 'src/app.ts',
          toFilePath: 'src/kept.ts',
          pluginId: 'existing-plugin',
        },
      ],
      symbols: [],
    }).relations).toEqual([
      {
        kind: 'import',
        sourceId: 'plugin:import',
        fromFilePath: 'src/app.ts',
        toFilePath: 'src/lib.ts',
        pluginId: 'plugin',
      },
      {
        kind: 'import',
        sourceId: 'plugin:kept',
        fromFilePath: 'src/app.ts',
        toFilePath: 'src/kept.ts',
        pluginId: 'existing-plugin',
      },
    ]);
  });

  it('preserves missing relations when adding plugin provenance', () => {
    const plugin = { id: 'plugin' } as IPlugin;

    expect(withPluginProvenance(plugin, {
      filePath: 'src/app.ts',
      edgeTypes: [],
      nodeTypes: [],
      nodes: [],
      symbols: [],
    })).toEqual({
      filePath: 'src/app.ts',
      edgeTypes: [],
      nodeTypes: [],
      nodes: [],
      symbols: [],
    });
  });

  it('projects file analysis relations into graph connections', () => {
    expect(toProjectedConnectionsFromFileAnalysis({
      filePath: 'src/app.ts',
      edgeTypes: [],
      nodeTypes: [],
      nodes: [],
      relations: [{
        kind: 'call',
        pluginId: 'plugin',
        sourceId: 'plugin:call',
        fromFilePath: 'src/app.ts',
        resolvedPath: 'src/lib.ts',
        type: 'dynamic',
        variant: 'async',
        metadata: { line: 10 },
      }],
      symbols: [],
    })).toEqual([{
      kind: 'call',
      pluginId: 'plugin',
      sourceId: 'plugin:call',
      specifier: '',
      resolvedPath: 'src/lib.ts',
      type: 'dynamic',
      variant: 'async',
      metadata: { line: 10 },
    }]);
  });

  it('returns no projected connections when the analysis has no relations', () => {
    expect(toProjectedConnectionsFromFileAnalysis({
      filePath: 'src/app.ts',
      edgeTypes: [],
      nodeTypes: [],
      nodes: [],
      symbols: [],
    })).toEqual([]);
  });
});

import { describe, expect, it } from 'vitest';
import type { IFileAnalysisResult } from '../../../../../src/core/plugins/types/contracts';
import {
  createEmptyFileAnalysisResult,
  mergeById,
  mergeFileAnalysisResults,
  mergeRelations,
} from '../../../../../src/core/plugins/routing/router/results/merge';

describe('routing/results/merge', () => {
  it('builds an empty analysis result for a file path', () => {
    expect(createEmptyFileAnalysisResult('src/app.ts')).toEqual({
      filePath: 'src/app.ts',
      edgeTypes: [],
      nodeTypes: [],
      nodes: [],
      relations: [],
      symbols: [],
    });
  });

  it('prefers later items when merging lists by id', () => {
    expect(
      mergeById(
        [{ id: 'file', label: 'File', defaultColor: '#aaa', defaultVisible: true }],
        [{ id: 'file', label: 'Updated', defaultColor: '#bbb', defaultVisible: false }],
      ),
    ).toEqual([{ id: 'file', label: 'Updated', defaultColor: '#bbb', defaultVisible: false }]);
  });

  it('keeps base items when no later items are provided', () => {
    expect(
      mergeById(
        [{ id: 'file', label: 'File', defaultColor: '#aaa', defaultVisible: true }],
        undefined,
      ),
    ).toEqual([{ id: 'file', label: 'File', defaultColor: '#aaa', defaultVisible: true }]);
  });

  it('treats missing item arrays as empty lists', () => {
    expect(mergeById(undefined, undefined)).toEqual([]);
    expect(
      mergeById(undefined, [
        { id: 'file', label: 'File', defaultColor: '#aaa', defaultVisible: true },
      ]),
    ).toEqual([{ id: 'file', label: 'File', defaultColor: '#aaa', defaultVisible: true }]);
  });

  it('deduplicates relations by the routed relation key', () => {
    expect(
      mergeRelations(
        [{
          kind: 'call',
          sourceId: 'call:run',
          fromFilePath: 'src/app.ts',
          fromSymbolId: 'src/app.ts:function:run',
          toFilePath: 'src/a.ts',
        }],
        [{
          kind: 'call',
          sourceId: 'call:run',
          fromFilePath: 'src/app.ts',
          fromSymbolId: 'src/app.ts:function:run',
          toFilePath: 'src/a.ts',
          metadata: { updated: true },
        }],
      ),
    ).toEqual([{
      kind: 'call',
      sourceId: 'call:run',
      fromFilePath: 'src/app.ts',
      fromSymbolId: 'src/app.ts:function:run',
      toFilePath: 'src/a.ts',
      metadata: { updated: true },
    }]);
  });

  it('keeps base relations when no later relations are provided', () => {
    expect(
      mergeRelations(
        [{
          kind: 'call',
          sourceId: 'call:run',
          fromFilePath: 'src/app.ts',
          fromSymbolId: 'src/app.ts:function:run',
          toFilePath: 'src/a.ts',
        }],
        undefined,
      ),
    ).toEqual([{
      kind: 'call',
      sourceId: 'call:run',
      fromFilePath: 'src/app.ts',
      fromSymbolId: 'src/app.ts:function:run',
      toFilePath: 'src/a.ts',
    }]);
  });

  it('treats missing relation arrays as empty lists', () => {
    expect(mergeRelations(undefined, undefined)).toEqual([]);
  });

  it('merges analysis results field by field', () => {
    const baseResult = createEmptyFileAnalysisResult('src/base.ts');
    const nextResult: IFileAnalysisResult = {
      filePath: 'src/next.ts',
      edgeTypes: [{ id: 'import', label: 'Import', defaultColor: '#38BDF8', defaultVisible: true }],
      nodeTypes: [{ id: 'file', label: 'File', defaultColor: '#A1A1AA', defaultVisible: true }],
      nodes: [{ id: 'src/app.ts', nodeType: 'file', label: 'app.ts' }],
      relations: [{
        kind: 'import' as const,
        sourceId: 'import:lib',
        fromFilePath: 'src/app.ts',
        toFilePath: 'src/lib.ts',
      }],
      symbols: [{
        id: 'src/app.ts:function:run',
        name: 'run',
        kind: 'function' as const,
        filePath: 'src/app.ts',
      }],
    };

    expect(mergeFileAnalysisResults(baseResult, nextResult)).toEqual(nextResult);
  });

  it('keeps the base file path when the next result omits it', () => {
    expect(
      mergeFileAnalysisResults(
        {
          ...createEmptyFileAnalysisResult('src/base.ts'),
          nodeTypes: [{ id: 'file', label: 'File', defaultColor: '#A1A1AA', defaultVisible: true }],
        },
        {
          ...createEmptyFileAnalysisResult(''),
          nodeTypes: [],
        },
      ),
    ).toEqual({
      filePath: 'src/base.ts',
      edgeTypes: [],
      nodeTypes: [{ id: 'file', label: 'File', defaultColor: '#A1A1AA', defaultVisible: true }],
      nodes: [],
      relations: [],
      symbols: [],
    });
  });
});

import { describe, expect, it } from 'vitest';
import { getRelationKey } from '../../../../../src/core/plugins/routing/router/results/keys';

describe('routing/results/keys', () => {
  it('serializes every base relation field in order and uses empty placeholders for missing optionals', () => {
    expect(
      getRelationKey({
        kind: 'import',
        sourceId: 'import:lib',
        fromFilePath: 'src/app.ts',
      } as never),
    ).toBe('import|import:lib|src/app.ts|||||');

    expect(
      getRelationKey({
        kind: 'import',
        sourceId: 'import:lib',
        fromFilePath: 'src/app.ts',
        fromNodeId: 'node-a',
        fromSymbolId: 'symbol-a',
        specifier: './lib',
        type: 'value',
        variant: 'static',
      } as never),
    ).toBe('import|import:lib|src/app.ts|node-a|symbol-a|./lib|value|static');
  });

  it('includes resolved target fields for call-like relations', () => {
    const baseRelation = {
      kind: 'call' as const,
      sourceId: 'call:run',
      fromFilePath: 'src/app.ts',
      fromSymbolId: 'src/app.ts:function:run',
      specifier: './lib',
    };

    expect(getRelationKey({ ...baseRelation, toFilePath: 'src/a.ts' })).not.toEqual(
      getRelationKey({ ...baseRelation, toFilePath: 'src/b.ts' }),
    );
  });

  it('includes every resolved target field for call and reference relations', () => {
    expect(
      getRelationKey({
        kind: 'call',
        sourceId: 'call:run',
        fromFilePath: 'src/app.ts',
        fromNodeId: 'caller-node',
        fromSymbolId: 'caller-symbol',
        specifier: './lib',
        type: 'value',
        variant: 'static',
        toFilePath: 'src/lib.ts',
        toNodeId: 'callee-node',
        toSymbolId: 'callee-symbol',
        resolvedPath: '/workspace/src/lib.ts',
      } as never),
    ).toBe(
      'call|call:run|src/app.ts|caller-node|caller-symbol|./lib|value|static|src/lib.ts|callee-node|callee-symbol|/workspace/src/lib.ts',
    );

    expect(
      getRelationKey({
        kind: 'reference',
        sourceId: 'reference:run',
        fromFilePath: 'src/app.ts',
        toFilePath: 'src/lib.ts',
      } as never),
    ).toBe('reference|reference:run|src/app.ts||||||src/lib.ts|||');
  });

  it('omits resolved target fields for non-call relations', () => {
    const baseRelation = {
      kind: 'import' as const,
      sourceId: 'import:lib',
      fromFilePath: 'src/app.ts',
      specifier: './lib',
    };

    expect(getRelationKey({ ...baseRelation, toFilePath: 'src/a.ts' })).toEqual(
      getRelationKey({ ...baseRelation, toFilePath: 'src/b.ts' }),
    );
  });

  it('uses pipe separators between every serialized relation segment', () => {
    expect(
      getRelationKey({
        kind: 'call',
        sourceId: 'call:run',
        fromFilePath: 'src/app.ts',
        toFilePath: 'src/lib.ts',
      } as never),
    ).toContain('|');
    expect(
      getRelationKey({
        kind: 'call',
        sourceId: 'call:run',
        fromFilePath: 'src/app.ts',
        toFilePath: 'src/lib.ts',
      } as never).split('|'),
    ).toHaveLength(12);
  });
});

